191	            assign fp_operand = lane_operand2;
192	            reciprocal_rom rom(
193	                .significand(fp_operand.significand[22:17]),
194	                .reciprocal_estimate);
195	
196	            always_comb
197	            begin
198	                if (fp_operand.exponent == 0)
199	                begin
200	                    // A subnormal will overflow the exponent field, so convert to infinity.
201	                    // This also handles division by zero.
202	                    reciprocal = {fp_operand.sign, 8'hff, 23'd0}; // inf
203	                end
204	                else if (fp_operand.exponent == 8'hff)
205	                begin
206	                    if (fp_operand.significand != 0)
207	                        reciprocal = {1'b0, 8'hff, 23'h7fffff}; // Division by NaN = NaN
208	                    else
209	                        reciprocal = {fp_operand.sign, 8'h00, 23'h000000}; // Division by +/-inf = +/-0.0
210	                end
211	                else
212	                begin
213	                    reciprocal = {fp_operand.sign, 8'd253 - fp_operand.exponent + 8'((fp_operand.significand[22:17] == 0)),
214	                        reciprocal_estimate, {17{1'b0}}};
215	                end
216	            end
217	
218	            always_comb
219	            begin
220	                unique case (of_instruction.alu_op)
221	                    OP_ASHR,
222	                    OP_SHR: lane_result = rshift;
223	                    OP_SHL: lane_result = lane_operand1 << lane_operand2[4:0];
224	                    OP_MOVE: lane_result = lane_operand2;
225	                    OP_OR: lane_result = lane_operand1 | lane_operand2;
226	                    OP_CLZ: lane_result = scalar_t'(lz);
227	                    OP_CTZ: lane_result = scalar_t'(tz);
228	                    OP_AND: lane_result = lane_operand1 & lane_operand2;
229	                    OP_XOR: lane_result = lane_operand1 ^ lane_operand2;
230	                    OP_ADD_I: lane_result = lane_operand1 + lane_operand2;
231	                    OP_SUB_I: lane_result = difference;
232	                    OP_CMPEQ_I: lane_result = {{31{1'b0}}, zero};
233	                    OP_CMPNE_I: lane_result = {{31{1'b0}}, !zero};
234	                    OP_CMPGT_I: lane_result = {{31{1'b0}}, signed_gtr && !zero};
235	                    OP_CMPGE_I: lane_result = {{31{1'b0}}, signed_gtr || zero};
236	                    OP_CMPLT_I: lane_result = {{31{1'b0}}, !signed_gtr && !zero};
237	                    OP_CMPLE_I: lane_result = {{31{1'b0}}, !signed_gtr || zero};
238	                    OP_CMPGT_U: lane_result = {{31{1'b0}}, !borrow && !zero};
239	                    OP_CMPGE_U: lane_result = {{31{1'b0}}, !borrow || zero};
240	                    OP_CMPLT_U: lane_result = {{31{1'b0}}, borrow && !zero};
241	                    OP_CMPLE_U: lane_result = {{31{1'b0}}, borrow || zero};
242	                    OP_SEXT8: lane_result = scalar_t'($signed(lane_operand2[7:0]));
243	                    OP_SEXT16: lane_result = scalar_t'($signed(lane_operand2[15:0]));
244	                    OP_SHUFFLE,
245	                    OP_GETLANE: lane_result = of_operand1[~lane_operand2];
246	                    OP_RECIPROCAL: lane_result = reciprocal;
247	                    default: lane_result = 0;
248	                endcase
249	            end
250	
251	            assign vector_result[lane] = lane_result;
252	        end
253	    endgenerate
254	
255	    assign valid_instruction = of_instruction_valid
256	        && (!wb_rollback_en || wb_rollback_thread_idx != of_thread_idx)
257	        && of_instruction.pipeline_sel == PIPE_INT_ARITH;
258	    assign eret = valid_instruction
259	        && of_instruction.branch
260	        && of_instruction.branch_type == BRANCH_ERET;
261	    assign privileged_op_fault = eret && !cr_supervisor_en[of_thread_idx];
262	
263	    always_comb
264	    begin
265	        branch_taken = 0;
266	        conditional_branch = 0;
267	
268	        if (valid_instruction
269	            && of_instruction.branch
270	            && !privileged_op_fault)
271	        begin
272	            unique case (of_instruction.branch_type)
273	                BRANCH_ZERO:
274	                begin
275	                    branch_taken = of_operand1[0] == 0;
276	                    conditional_branch = 1;
277	                end
278	
279	                BRANCH_NOT_ZERO:
280	                begin
281	                    branch_taken = of_operand1[0] != 0;
282	                    conditional_branch = 1;
283	                end
284	
285	                BRANCH_ALWAYS,
286	                BRANCH_CALL_OFFSET,
287	                BRANCH_CALL_REGISTER,
288	                BRANCH_REGISTER,
289	                BRANCH_ERET:
290	                begin
291	                    branch_taken = 1;
292	                end
293	
294	                default:
295	                    ;
296	            endcase
297	        end
298	    end
299	
300	
301	    always_ff @(posedge clk)
302	    begin
303	        ix_instruction <= of_instruction;
304	        ix_result <= vector_result;
305	        ix_mask_value <= of_mask_value;
306	        ix_thread_idx <= of_thread_idx;
307	        ix_subcycle <= of_subcycle;
308	
309	        // Branch handling
310	        unique case (of_instruction.branch_type)
311	            BRANCH_CALL_REGISTER,
312	            BRANCH_REGISTER: ix_rollback_pc <= of_operand1[0];
313	            BRANCH_ERET: ix_rollback_pc <= cr_eret_address[of_thread_idx];
314	            default:
315	                ix_rollback_pc <= of_instruction.pc + of_instruction.immediate_value;
316	        endcase
317	    end
318	
319	    always_ff @(posedge clk, posedge reset)
320	    begin
321	        if (reset)
322	        begin
323	            /*AUTORESET*/
324	            // Beginning of autoreset for uninitialized flops
325	            ix_instruction_valid <= '0;
326	            ix_perf_cond_branch_not_taken <= '0;
327	            ix_perf_cond_branch_taken <= '0;
328	            ix_perf_uncond_branch <= '0;
329	            ix_privileged_op_fault <= '0;
330	            ix_rollback_en <= '0;
331	            // End of automatics
332	        end
333	        else
334	        begin
335	            if (valid_instruction)
336	            begin
337	                ix_instruction_valid <= 1;
338	                ix_privileged_op_fault <= privileged_op_fault;
339	                ix_rollback_en <= branch_taken;
340	            end
341	            else
342	            begin
343	                ix_instruction_valid <= 0;
344	                ix_rollback_en <= 0;
345	            end
346	
347	            ix_perf_uncond_branch <= !conditional_branch && branch_taken;
348	            ix_perf_cond_branch_taken <= conditional_branch && branch_taken;
349	            ix_perf_cond_branch_not_taken <= conditional_branch && !branch_taken;
350	        end
351	    end
352	endmodule
